import React from 'react';
import { FontAwesomeIcon } from '@fortawesome/react-fontawesome';
import { faHeart, faChevronUp } from '@fortawesome/free-solid-svg-icons';
import { useWishlist } from '../context/WishlistContext';
import './BottomBar.css';

export default function BottomBar() {
  const { totalItems, subtotal, setIsDrawerOpen } = useWishlist();

  if (totalItems === 0) return null;

  return (
    <div className="bottom-bar" onClick={() => setIsDrawerOpen(true)}>
      <div className="bottom-bar__inner">
        <div className="bottom-bar__left">
          <div className="bottom-bar__icon">
            <FontAwesomeIcon icon={faHeart} />
            <span className="bottom-bar__count">{totalItems}</span>
          </div>
          <span className="font-label-md bottom-bar__text">
            {totalItems} item{totalItems > 1 ? 's' : ''} in wishlist
          </span>
        </div>
        <div className="bottom-bar__right">
          <span className="font-label-md bottom-bar__price">₹{subtotal.toLocaleString()}</span>
          <FontAwesomeIcon icon={faChevronUp} className="bottom-bar__chevron" />
        </div>
      </div>
    </div>
  );
}
